ToolDef {
    name: "scratchpad_create",
    description: "Create a new scratchpad with a title. Returns its numeric id.",
    schema_fn: schema_for::<ScratchpadCreateArgs>,
},
ToolDef {
    name: "scratchpad_list",
    description: "List all scratchpads as a JSON array of {id, title}.",
    schema_fn: schema_for_no_args,
},
ToolDef {
    name: "scratchpad_append",
    description: "Append text to an existing scratchpad, addressed by numeric id.",
    schema_fn: schema_for::<ScratchpadAppendArgs>,
},
ToolDef {
    name: "scratchpad_read",
    description: "Read the full body of a scratchpad, addressed by numeric id.",
    schema_fn: schema_for::<ScratchpadReadArgs>,
},
ToolDef {
    name: "scratchpad_get",
    description: "Fetch one scratchpad in full - id, title, body, and timestamps - \
                  addressed by numeric id.",
    schema_fn: schema_for::<ScratchpadGetArgs>,
},
ToolDef {
    name: "scratchpad_update",
    description: "Edit a scratchpad's title, body, and/or tags. Each omitted field is left \
                  unchanged; body replaces the existing body in full (use \
                  scratchpad_append to add instead of replace); tags replaces the whole \
                  tag list.",
    schema_fn: schema_for::<ScratchpadUpdateArgs>,
},
ToolDef {
    name: "scratchpad_delete",
    description: "Delete a scratchpad. Removes both the database row and the per-pad \
                  projection file.",
    schema_fn: schema_for::<ScratchpadDeleteArgs>,
},
ToolDef {
    name: "scratchpad_tags_list",
    description: "List the project's tag vocabulary: the sorted, deduped union of every \
                  tag attached to any todo OR scratchpad. Identical output to \
                  todo_tags_list - the two surfaces share one project-wide tag pool.",
    schema_fn: schema_for_no_args,
},
ToolDef {
    name: "todo_create",
    description: "Create a new todo with a title. Returns its numeric id.",
    schema_fn: schema_for::<TodoCreateArgs>,
},
ToolDef {
    name: "todo_list",
    description: "List all todos as a JSON array of {id, title, status, priority, \
                  assignee, tags, blockers, comment_count, created_at, updated_at}. \
                  Use todo_get for a todo's body and comment thread.",
    schema_fn: schema_for_no_args,
},
ToolDef {
    name: "todo_get",
    description: "Fetch one todo in full - body, comment thread, blockers and all - \
                  addressed by numeric id. `locked_by` is set when an agent holds \
                  the `todo:<id>` advisory lock.",
    schema_fn: schema_for::<TodoGetArgs>,
},
ToolDef {
    name: "todo_update",
    description: "Edit a todo's fields. Every argument but todo_id is optional; an \
                  omitted field is left unchanged. status is one of open/in_progress/\
                  backlog/draft/completed/not_done, priority one of high/medium/low; tags \
                  replaces the whole tag list.",
    schema_fn: schema_for::<TodoUpdateArgs>,
},
ToolDef {
    name: "todo_complete",
    description: "Mark a todo complete, addressed by numeric id.",
    schema_fn: schema_for::<TodoCompleteArgs>,
},
ToolDef {
    name: "todo_start",
    description: "Claim a todo for active work: atomically acquires the `todo:<id>` \
                  advisory lock, transitions status to `in_progress`, and returns the \
                  same full detail as `todo_get`. Use this as the first MCP call when \
                  you start work on a todo (e.g. the user asks 'do #N'). Idempotent \
                  when you already hold the lock and the todo is `in_progress`. If \
                  another agent holds the lock, returns {started: false, held_by} \
                  without mutating status. Errors on terminal states \
                  (`completed`/`not_done`) - reopen via `todo_update` first.",
    schema_fn: schema_for::<TodoStartArgs>,
},
ToolDef {
    name: "todo_delete",
    description: "Delete a todo, addressed by numeric id. Its comments and blocker \
                  links are removed with it.",
    schema_fn: schema_for::<TodoDeleteArgs>,
},
ToolDef {
    name: "todo_add_blocker",
    description: "Record that one todo is blocked by another: todo_id is blocked by \
                  blocker_id. Both must exist and must differ.",
    schema_fn: schema_for::<TodoBlockerArgs>,
},
ToolDef {
    name: "todo_remove_blocker",
    description: "Remove a blocker link, so todo_id is no longer blocked by \
                  blocker_id.",
    schema_fn: schema_for::<TodoBlockerArgs>,
},
ToolDef {
    name: "todo_comment_add",
    description: "Add a comment to a todo. The author is the supplied `author`, or - \
                  omitted - the calling agent's registered name. Returns the new \
                  comment's numeric id.",
    schema_fn: schema_for::<TodoCommentAddArgs>,
},
ToolDef {
    name: "todo_comment_update",
    description: "Edit an existing comment's body. The author and timestamp are \
                  preserved - this is not a re-post.",
    schema_fn: schema_for::<TodoCommentUpdateArgs>,
},
ToolDef {
    name: "todo_comment_delete",
    description: "Delete a comment from a todo. Comment ids are not reused after \
                  deletion - the per-todo counter keeps advancing.",
    schema_fn: schema_for::<TodoCommentDeleteArgs>,
},
ToolDef {
    name: "todo_set_blockers",
    description: "Replace a todo's blocker set in one call. Equivalent to a diff of \
                  todo_add_blocker / todo_remove_blocker, but atomic - used by the \
                  cockpit form to avoid a half-applied state.",
    schema_fn: schema_for::<TodoSetBlockersArgs>,
},
ToolDef {
    name: "todo_tags_list",
    description: "List the project's tag vocabulary: the sorted, deduped union of \
                  every tag attached to any todo OR scratchpad. The two surfaces \
                  share one project-wide tag pool, so this returns identical output \
                  to scratchpad_tags_list.",
    schema_fn: schema_for_no_args,
},
ToolDef {
    name: "todo_lock",
    description: "Claim a todo as `todo:<id>` in the advisory lock table. A thin \
                  wrapper around lock_acquire - non-blocking, returns {acquired: \
                  bool, held_by?: name}. Advisory only.",
    schema_fn: schema_for::<TodoLockArgs>,
},
ToolDef {
    name: "todo_unlock",
    description: "Release the `todo:<id>` advisory lock you hold. Returns \
                  {released: bool, held_by?: name}.",
    schema_fn: schema_for::<TodoUnlockArgs>,
},
ToolDef {
    name: "agent_tool_create",
    description: "Create an agent tool (config layer) - a durable agent configuration \
                  this project can spawn processes from. Returns its numeric id.",
    schema_fn: schema_for::<AgentToolCreateArgs>,
},
ToolDef {
    name: "agent_tool_list",
    description: "List this project's agent tools as a JSON array of {id, name, \
                  display_name, command, cwd, tool_type, enabled, position, created_at}.",
    schema_fn: schema_for_no_args,
},
ToolDef {
    name: "agent_tool_get",
    description: "Fetch one agent tool in full, addressed by numeric id.",
    schema_fn: schema_for::<AgentToolGetArgs>,
},
ToolDef {
    name: "agent_tool_update",
    description: "Edit an agent tool's fields. Every argument but agent_tool_id is \
                  optional; an omitted field is left unchanged.",
    schema_fn: schema_for::<AgentToolUpdateArgs>,

//! Request parameter structs for the MCP tools.
//!
//! Each derives `Deserialize` + `JsonSchema` so the surface table in
//! [`crate`] can generate each tool's input schema, and so panoptd can
//! deserialize incoming tool-call arguments. Doc comments on the fields
//! become the parameter descriptions agents see.
//!
//! `schemars` is re-exported from [`crate`] (and used directly here) at the
//! version pinned by this crate's Cargo.toml; both panoptd and the proxy
//! see the same schemars, so the schemas the proxy publishes are
//! bit-identical to the ones panoptd deserializes against.

use schemars::JsonSchema;
use serde::Deserialize;

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ScratchpadCreateArgs {
    /// Human-readable title for the new scratchpad.
    pub title: String,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ScratchpadAppendArgs {
    /// Numeric id of the scratchpad to append to.
    pub scratchpad_id: u64,
    /// Text to append. It is placed on its own line after existing content.
    pub content: String,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ScratchpadReadArgs {
    /// Numeric id of the scratchpad to read.
    pub scratchpad_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ScratchpadGetArgs {
    /// Numeric id of the scratchpad to fetch in full.
    pub scratchpad_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ScratchpadUpdateArgs {
    /// Numeric id of the scratchpad to edit.
    pub scratchpad_id: u64,
    /// New title. Omit to leave unchanged.
    #[serde(default)]
    pub title: Option<String>,
    /// Replacement body. Replaces the existing body in full. Omit to leave
    /// unchanged.
    #[serde(default)]
    pub body: Option<String>,
    /// New complete tag list, replacing the old one. Tags share a project-wide
    /// vocabulary with todos (see `scratchpad_tags_list`). Omit to leave
    /// unchanged.
    #[serde(default)]
    pub tags: Option<Vec<String>>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ScratchpadDeleteArgs {
    /// Numeric id of the scratchpad to delete.
    pub scratchpad_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoCreateArgs {
    /// Short description of the todo.
    pub title: String,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoCompleteArgs {
    /// Numeric id of the todo to mark complete.
    pub todo_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoStartArgs {
    /// Numeric id of the todo to claim and transition to `in_progress`.
    pub todo_id: u64,
    /// Optional reason, forwarded to the `todo:<id>` advisory lock and shown
    /// to other agents in `lock_status`.
    #[serde(default)]
    pub note: Option<String>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoGetArgs {
    /// Numeric id of the todo to fetch.
    pub todo_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct IdKindArgs {
    /// Numeric id to resolve to its resource kind.
    pub id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoDeleteArgs {
    /// Numeric id of the todo to delete. Its comments and blocker links go too.
    pub todo_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoUpdateArgs {
    /// Numeric id of the todo to edit.
    pub todo_id: u64,
    /// New title. Omit to leave unchanged.
    #[serde(default)]
    pub title: Option<String>,
    /// New free-form description body. Omit to leave unchanged.
    #[serde(default)]
    pub body: Option<String>,
    /// New status: one of open, in_progress, backlog, draft, completed,
    /// not_done. Omit to leave unchanged.
    #[serde(default)]
    pub status: Option<String>,
    /// New priority: one of high, medium, low. Omit to leave unchanged.
    #[serde(default)]
    pub priority: Option<String>,
    /// New assignee name, or an empty string to clear it. Omit to leave
    /// unchanged.
    #[serde(default)]
    pub assignee: Option<String>,
    /// New complete tag list, replacing the old one. Omit to leave unchanged.
    #[serde(default)]
    pub tags: Option<Vec<String>>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoBlockerArgs {
    /// Numeric id of the blocked todo.
    pub todo_id: u64,
    /// Numeric id of the todo that blocks it.
    pub blocker_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoCommentAddArgs {
    /// Numeric id of the todo to comment on.
    pub todo_id: u64,
    /// Comment text.
    pub body: String,
    /// Author name to record. Omit to use the calling agent's registered name;
    /// a non-agent caller (the `panopt` CLI) supplies this explicitly.
    #[serde(default)]
    pub author: Option<String>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoCommentUpdateArgs {
    /// Numeric id of the todo the comment lives on.
    pub todo_id: u64,
    /// Numeric id of the comment to edit (per-todo, restarts at 1 in each todo).
    pub comment_id: u64,
    /// Replacement body. The author and timestamp are preserved.
    pub body: String,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoCommentDeleteArgs {
    /// Numeric id of the todo the comment lives on.
    pub todo_id: u64,
    /// Numeric id of the comment to delete.
    pub comment_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoSetBlockersArgs {
    /// Numeric id of the todo whose blocker set is being replaced.
    pub todo_id: u64,
    /// Replacement set of blocker ids. May be empty to clear all blockers.
    pub blocker_ids: Vec<u64>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoLockArgs {
    /// Numeric id of the todo to claim. The advisory lock name is `todo:<id>`.
    pub todo_id: u64,
    /// Optional reason, shown to other agents in `lock_status`.
    #[serde(default)]
    pub note: Option<String>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct TodoUnlockArgs {
    /// Numeric id of the todo whose lock to release.
    pub todo_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct AgentToolCreateArgs {
    /// Identifier-style name for the tool (e.g. "claude").
    pub name: String,
    /// Optional human label shown in the cockpit. Omit to use `name`.
    #[serde(default)]
    pub display_name: Option<String>,
    /// Shell command this tool launches when a process is spawned from it.
    #[serde(default)]
    pub command: Option<String>,
    /// Working directory passed to the launched command. Omit to use project root.
    #[serde(default)]
    pub cwd: Option<String>,
    /// Free-form tag for future categorization. Defaults to "agent".
    #[serde(default)]
    pub tool_type: Option<String>,
    /// Whether the tool is offered in spawn UIs. Defaults to true.
    #[serde(default)]
    pub enabled: Option<bool>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct AgentToolGetArgs {
    /// Numeric id of the agent tool to fetch.
    pub agent_tool_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct AgentToolUpdateArgs {
    /// Numeric id of the agent tool to edit.
    pub agent_tool_id: u64,
    /// New name. Omit to leave unchanged.
    #[serde(default)]
    pub name: Option<String>,
    /// New display label. Omit to leave unchanged.
    #[serde(default)]
    pub display_name: Option<String>,
    /// New launch command. Omit to leave unchanged.
    #[serde(default)]
    pub command: Option<String>,
    /// New working directory. Omit to leave unchanged.
    #[serde(default)]
    pub cwd: Option<String>,
    /// New tool_type tag. Omit to leave unchanged.
    #[serde(default)]
    pub tool_type: Option<String>,
    /// New enabled flag. Omit to leave unchanged.
    #[serde(default)]
    pub enabled: Option<bool>,
    /// New sort position. Omit to leave unchanged.
    #[serde(default)]
    pub position: Option<i64>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct AgentToolDeleteArgs {
    /// Numeric id of the agent tool to delete.
    pub agent_tool_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ProcessCreateArgs {
    /// Kind of process: one of agent, command, terminal.
    pub kind: String,
    /// Identifier-style name for the process.
    pub name: String,
    /// Optional human label shown in the cockpit. Omit to use `name`.
    #[serde(default)]
    pub display_name: Option<String>,
    /// Shell command the process executes. Omit for a bare terminal.
    #[serde(default)]
    pub command: Option<String>,
    /// Working directory for the process. Omit to use project root.
    #[serde(default)]
    pub cwd: Option<String>,
    /// Numeric id of the agent tool this process was spawned from. Omit for
    /// command and terminal processes that have no backing config.
    #[serde(default)]
    pub agent_tool_id: Option<u64>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ProcessGetArgs {
    /// Numeric id of the process to fetch.
    pub process_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ProcessUpdateArgs {
    /// Numeric id of the process to edit.
    pub process_id: u64,
    /// New name. Omit to leave unchanged.
    #[serde(default)]
    pub name: Option<String>,
    /// New display label. Omit to leave unchanged.
    #[serde(default)]
    pub display_name: Option<String>,
    /// New launch command. Omit to leave unchanged.
    #[serde(default)]
    pub command: Option<String>,
    /// New working directory. Omit to leave unchanged.
    #[serde(default)]
    pub cwd: Option<String>,
    /// New sort position. Omit to leave unchanged.
    #[serde(default)]
    pub position: Option<i64>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct ProcessDeleteArgs {
    /// Numeric id of the process to delete.
    pub process_id: u64,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct IdentifyArgs {
    /// Human-readable name for this agent, shown to others in the registry.
    pub name: String,
    /// Optional free-form status, for example "implementing auth" or "blocked".
    #[serde(default)]
    pub status: Option<String>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct LockAcquireArgs {
    /// Name of the advisory lock to acquire - an agreed-on string such as a
    /// path, a task, or a phase of work.
    pub name: String,
    /// Optional reason for holding the lock, shown to other agents.
    #[serde(default)]
    pub note: Option<String>,
}

#[derive(Debug, Deserialize, JsonSchema)]
pub struct LockReleaseArgs {
    /// Name of the advisory lock to release.
    pub name: String,
}

