1261	/// Every tool name in [`TOOL_SURFACE`], promoted to an enum so [`dispatch_local`]'s
1262	/// `match` is exhaustive: adding a new tool here forces a corresponding
1263	/// dispatch arm at compile time. The unit test `tool_enum_covers_tool_surface`
1264	/// asserts the inverse - that every surface entry resolves through [`Tool::from_name`].
1265	#[derive(Clone, Copy)]
1266	enum Tool {
1267	    Identify,
1268	    AgentLeave,
1269	    Whoami,
1270	    AgentList,
1271	    LockAcquire,
1272	    LockRelease,
1273	    LockStatus,
1274	    ScratchpadCreate,
1275	    ScratchpadList,
1276	    ScratchpadAppend,
1277	    ScratchpadRead,
1278	    ScratchpadGet,
1279	    ScratchpadUpdate,
1280	    ScratchpadDelete,
1281	    ScratchpadTagsList,
1282	    TodoCreate,
1283	    TodoList,
1284	    TodoGet,
1285	    TodoUpdate,
1286	    TodoComplete,
1287	    TodoStart,
1288	    TodoDelete,
1289	    TodoAddBlocker,
1290	    TodoRemoveBlocker,
1291	    TodoCommentAdd,
1292	    TodoCommentUpdate,
1293	    TodoCommentDelete,
1294	    TodoSetBlockers,
1295	    TodoTagsList,
1296	    TodoLock,
1297	    TodoUnlock,
1298	    AgentToolCreate,
1299	    AgentToolList,
1300	    AgentToolGet,
1301	    AgentToolUpdate,
1302	    AgentToolDelete,
1303	    ProcessCreate,
1304	    ProcessList,
1305	    ProcessGet,
1306	    ProcessUpdate,
1307	    ProcessDelete,
1308	    IdKind,
1309	}
1310	
1311	impl Tool {
1312	    fn from_name(name: &str) -> Option<Self> {
1313	        Some(match name {
1314	            "identify" => Tool::Identify,
1315	            "agent_leave" => Tool::AgentLeave,
1316	            "whoami" => Tool::Whoami,
1317	            "agent_list" => Tool::AgentList,
1318	            "lock_acquire" => Tool::LockAcquire,
1319	            "lock_release" => Tool::LockRelease,
1320	            "lock_status" => Tool::LockStatus,
1321	            "scratchpad_create" => Tool::ScratchpadCreate,
1322	            "scratchpad_list" => Tool::ScratchpadList,
1323	            "scratchpad_append" => Tool::ScratchpadAppend,
1324	            "scratchpad_read" => Tool::ScratchpadRead,
1325	            "scratchpad_get" => Tool::ScratchpadGet,
1326	            "scratchpad_update" => Tool::ScratchpadUpdate,
1327	            "scratchpad_delete" => Tool::ScratchpadDelete,
1328	            "scratchpad_tags_list" => Tool::ScratchpadTagsList,
1329	            "todo_create" => Tool::TodoCreate,
1330	            "todo_list" => Tool::TodoList,
1331	            "todo_get" => Tool::TodoGet,
1332	            "todo_update" => Tool::TodoUpdate,
1333	            "todo_complete" => Tool::TodoComplete,
1334	            "todo_start" => Tool::TodoStart,
1335	            "todo_delete" => Tool::TodoDelete,
1336	            "todo_add_blocker" => Tool::TodoAddBlocker,
1337	            "todo_remove_blocker" => Tool::TodoRemoveBlocker,
1338	            "todo_comment_add" => Tool::TodoCommentAdd,
1339	            "todo_comment_update" => Tool::TodoCommentUpdate,
1340	            "todo_comment_delete" => Tool::TodoCommentDelete,
1341	            "todo_set_blockers" => Tool::TodoSetBlockers,
1342	            "todo_tags_list" => Tool::TodoTagsList,
1343	            "todo_lock" => Tool::TodoLock,
1344	            "todo_unlock" => Tool::TodoUnlock,
1345	            "agent_tool_create" => Tool::AgentToolCreate,
1346	            "agent_tool_list" => Tool::AgentToolList,
1347	            "agent_tool_get" => Tool::AgentToolGet,
1348	            "agent_tool_update" => Tool::AgentToolUpdate,
1349	            "agent_tool_delete" => Tool::AgentToolDelete,
1350	            "process_create" => Tool::ProcessCreate,
1351	            "process_list" => Tool::ProcessList,
1352	            "process_get" => Tool::ProcessGet,
1353	            "process_update" => Tool::ProcessUpdate,
1354	            "process_delete" => Tool::ProcessDelete,
1355	            "id_kind" => Tool::IdKind,
1356	            _ => return None,
1357	        })
1358	    }
1359	}
1360	
1361	/// Build the rmcp `ToolRouter` from [`TOOL_SURFACE`].
1362	///
1363	/// One `add_route` per entry. The handler closure is uniform: every tool
1364	/// funnels through [`dispatch_local`], which keys off the tool name. This is
1365	/// the only place rmcp's `ToolRoute`/`Tool` types are constructed, so any
1366	/// schema-shape surprise from the shared crate surfaces here at registration
1367	/// rather than at first-call.
1368	fn build_router() -> ToolRouter<Handler> {
1369	    let mut router = ToolRouter::<Handler>::new();
1370	    for def in TOOL_SURFACE {
1371	        let name: &'static str = def.name;
1372	        let schema_obj = match (def.schema_fn)() {
1373	            serde_json::Value::Object(m) => m,
1374	            other => panic!("TOOL_SURFACE entry `{name}` produced a non-object schema: {other:?}"),
1375	        };
1376	        let attr = rmcp::model::Tool::new(name, def.description, Arc::new(schema_obj));
1377	        router.add_route(ToolRoute::new_dyn(attr, move |ctx| {
1378	            Box::pin(dispatch_local(name, ctx))
1379	        }));
1380	    }
1381	    router
1382	}
1383	
1384	/// Route an incoming tool call to its impl on [`Handler`].
1385	///
1386	/// Pulls the `http::request::Parts` extension that `main.rs` injects per
1387	/// request, deserializes the JSON arguments into the tool's `Parameters<T>`
1388	/// type from `panopt_tool_surface::params`, then calls the corresponding
1389	/// async method on `Handler`. The `match` over [`Tool`] is exhaustive, so the
1390	/// compiler rejects a new tool added without a dispatch arm.
1391	async fn dispatch_local<'a>(
1392	    name: &'static str,
1393	    ctx: ToolCallContext<'a, Handler>,
1394	) -> Result<CallToolResult, McpError> {
1395	    let tool = Tool::from_name(name)
1396	        .ok_or_else(|| McpError::invalid_params(format!("unknown tool `{name}`"), None))?;
1397	    let parts = ctx
1398	        .request_context
1399	        .extensions
1400	        .get::<Parts>()
1401	        .cloned()
1402	        .ok_or_else(|| {
1403	            McpError::internal_error(
1404	                "the request is missing its http::request::Parts extension",
1405	                None,
1406	            )
1407	        })?;
1408	    let handler = ctx.service;
1409	    let raw_args = ctx.arguments.unwrap_or_default();
1410	    match tool {
1411	        Tool::Identify => {
1412	            let args: IdentifyArgs = parse_json_object(raw_args)?;
