                      is_self}.",
        schema_fn: schema_for_no_args,
    },
    ToolDef {
        name: "agent_list",
        description: "List every agent currently connected to this project as a JSON array \
                      of {name, status, idle_seconds, is_self}.",
        schema_fn: schema_for_no_args,
    },
    ToolDef {
