            project,
            args.query.as_deref(),
            status,
            priority,
            args.assignee.as_deref(),
            &tags,
        )
        .map_err(map_core_err)?
        .iter()
        .map(TodoSummaryDto::from_todo)
        .collect()
    };
    json_result(&dtos)
}

