1	//! `panopt _mcp-proxy` - a long-lived stdio MCP server that fronts panoptd.
2	//!
3	//! Claude Code spawns this at session start via `--mcp-config` type=stdio.
4	//! The proxy speaks MCP-over-stdio to Claude Code and MCP-over-HTTP to
5	//! panoptd, owning the panoptd session-id and reconnecting transparently
6	//! across daemon restarts. From Claude Code's point of view, panoptd never
7	//! goes away: a `just refresh` only stalls the next tool call for the time
8	//! it takes the new daemon to come up.
9	//!
10	//! Two transports, two MCP sessions:
11	//!
12	//! - The stdio side is a tiny MCP server. The proxy answers `initialize` and
13	//!   `notifications/initialized` itself (so Claude Code sees a stable
14	//!   server), and forwards everything else - `tools/list`, `tools/call`,
15	//!   future methods - to panoptd verbatim. The JSON-RPC `id` is preserved
16	//!   so the response correlates on Claude Code's side without rewrite.
17	//! - The HTTP side is the panoptd Streamable HTTP endpoint, scoped to this
18	//!   agent by `?ws=&agent=&name=&token=` baked into the URL. The proxy
19	//!   maintains its own `mcp-session-id` here. When a forwarded request
20	//!   fails (the daemon was killed, returned 4xx for an unknown session,
21	//!   refused the TCP connection), the proxy drops the session-id, re-runs
22	//!   `initialize` + `notifications/initialized`, and replays the original
23	//!   request - all invisible to Claude Code.
24	//!
25	//! Outage policy: hybrid. Each forwarded call retries against panoptd with
26	//! exponential backoff for up to [`RECONNECT_BUDGET`]. Short outages (a
27	//! `just refresh`, a brief daemon hiccup) look like a slow tool call to
28	//! Claude Code, no error. Longer outages fail with a JSON-RPC error so the
29	//! Claude Code conversation surface gets a visible failure rather than
30	//! hanging indefinitely.
31	//!
32	//! `tools/list` is answered locally from [`panopt_tool_surface::TOOL_SURFACE`],
33	//! the same table panoptd registers its routes from. That makes a cold start
34	//! with a dead daemon survivable: Claude Code learns the tool surface
35	//! immediately and the first `tools/call` is the first thing that has to wait
36	//! on a real panoptd connection. Without this local answer, an unreachable
37	//! daemon at startup would force Claude's `tools/list` request to error out
38	//! (the MCP spec doesn't mandate a retry) and the panopt MCP server would
39	//! appear toolless for the rest of the session.
40	
41	use std::io::{stdin, stdout, BufRead, BufReader, Write};
42	use std::path::{Path, PathBuf};
43	use std::thread;
44	use std::time::{Duration, Instant};
45	
46	use anyhow::{anyhow, bail, Context, Result};
47	use percent_encoding::{utf8_percent_encode, NON_ALPHANUMERIC};
48	use serde_json::{json, Value};
49	
50	/// The MCP protocol version the proxy advertises to Claude Code, and the
51	/// version it uses in its own `initialize` against panoptd. Kept aligned
52	/// with `mcpclient.rs` so the two sides speak the same protocol revision.
53	const PROTOCOL_VERSION: &str = "2025-06-18";
54	
55	/// How long a single forwarded request keeps retrying against panoptd
56	/// before giving up and returning a JSON-RPC error to Claude Code. Long
57	/// enough to cover a full `cargo build && cargo run` rebuild cycle, short
58	/// enough that a genuinely-dead daemon does not hang the conversation.
59	const RECONNECT_BUDGET: Duration = Duration::from_secs(30);
60	
61	/// Initial delay between reconnect attempts. Doubles up to
62	/// [`RECONNECT_BACKOFF_MAX`] so we hammer the daemon during the brief
63	/// shutdown-to-startup window without busy-spinning if it stays down.
64	const RECONNECT_BACKOFF_INITIAL: Duration = Duration::from_millis(200);
65	
66	/// Upper bound on the reconnect interval.
67	const RECONNECT_BACKOFF_MAX: Duration = Duration::from_secs(2);
68	
69	/// `panopt _mcp-proxy` entry point. Blocks until stdin closes (Claude Code
70	/// has gone away).
71	pub fn run(
72	    host: String,
73	    port: u16,
74	    ws: PathBuf,
75	    id: String,
76	    name: String,
77	    token: String,
78	) -> Result<()> {
79	    let url = build_url(&host, port, &ws, &id, &name, &token);
80	    let mut backend = Backend::new(url, id, name);
81	
82	    // Eagerly bring up the panoptd session so the agent registers in the
83	    // roster before its first tool call. Failure here is non-fatal: the
84	    // next forwarded request will retry the same connection sequence, so a
85	    // daemon that boots a little later still picks the agent up.
86	    if let Err(e) = backend.connect() {
87	        eprintln!("panopt-proxy: initial panoptd connect failed (will retry on first call): {e:#}");
88	    }
89	
90	    let stdin = stdin();
91	    let mut stdout = stdout().lock();
92	    let mut reader = BufReader::new(stdin.lock());
93	    let mut line = String::new();
94	
95	    loop {
96	        line.clear();
97	        let n = reader.read_line(&mut line).context("reading stdin")?;
98	        if n == 0 {
99	            break; // Claude Code closed stdin - session over.
100	        }
101	        let trimmed = line.trim();
102	        if trimmed.is_empty() {
103	            continue;
104	        }
105	        let req: Value = match serde_json::from_str(trimmed) {
106	            Ok(v) => v,
107	            Err(e) => {
108	                eprintln!("panopt-proxy: malformed JSON-RPC frame ignored: {e}");
109	                continue;
110	            }
111	        };
112	        if let Some(resp) = dispatch(&mut backend, &req) {
113	            let serialized = serde_json::to_string(&resp).expect("response must serialize as JSON");
114	            writeln!(stdout, "{serialized}").context("writing to stdout")?;
115	            stdout.flush().context("flushing stdout")?;
116	        }
117	    }
118	
119	    backend.farewell();
120	    Ok(())
121	}
122	
123	fn build_url(host: &str, port: u16, ws: &Path, id: &str, name: &str, token: &str) -> String {
124	    let encode = |s: &str| utf8_percent_encode(s, NON_ALPHANUMERIC).to_string();
125	    format!(
126	        "http://{host}:{port}/mcp?ws={}&agent={}&name={}&token={}",
127	        encode(&ws.to_string_lossy()),
128	        encode(id),
129	        encode(name),
130	        encode(token),
131	    )
132	}
133	
134	/// Route a JSON-RPC request: answer the lifecycle methods and `tools/list`
135	/// locally, forward everything else to panoptd. Returns `Some(response)` for
136	/// requests (those carrying an `id`) and `None` for notifications.
137	fn dispatch(backend: &mut Backend, req: &Value) -> Option<Value> {
138	    let method = req.get("method").and_then(Value::as_str)?;
139	    let id = req.get("id").cloned();
140	    match method {
141	        "initialize" => Some(handle_initialize(backend, id)),
142	        "notifications/initialized" => None,
143	        "tools/list" => Some(handle_tools_list(id)),
144	        _ => Some(forward_or_error(backend, req, id)),
145	    }
146	}
147	
148	/// Respond to `tools/list` from the shared [`TOOL_SURFACE`] table.
149	///
150	/// Same data panoptd uses to register its routes, so the proxy's published
151	/// surface and the daemon's served surface cannot drift apart at build time.
152	/// The schema for each tool is materialized by calling that entry's
153	/// `schema_fn` - identical bytes to what panoptd emits, because both sides
154	/// route through `panopt_tool_surface::schema_for::<T>`.
155	fn handle_tools_list(id: Option<Value>) -> Value {
156	    let tools: Vec<Value> = panopt_tool_surface::TOOL_SURFACE
157	        .iter()
158	        .map(|def| {
159	            json!({
160	                "name": def.name,
161	                "description": def.description,
162	                "inputSchema": (def.schema_fn)(),
163	            })
164	        })
165	        .collect();
166	    json!({
167	        "jsonrpc": "2.0",
168	        "id": id,
169	        "result": { "tools": tools },
170	    })
171	}
172	
173	/// Respond to Claude Code's `initialize` without forwarding. The proxy is
174	/// its own MCP server from Claude Code's perspective; the panoptd session
175	/// is independent and was (or will be) initialized via [`Backend::connect`].
176	fn handle_initialize(_backend: &mut Backend, id: Option<Value>) -> Value {
177	    json!({
178	        "jsonrpc": "2.0",
179	        "id": id,
180	        "result": {
181	            "protocolVersion": PROTOCOL_VERSION,
182	            "capabilities": { "tools": {} },
183	            "serverInfo": {
184	                "name": "panopt-proxy",
185	                "version": env!("CARGO_PKG_VERSION"),
186	            },
187	        },
188	    })
189	}
190	
191	/// Forward `req` to panoptd. On unrecoverable failure (the
192	/// [`RECONNECT_BUDGET`] elapsed), return a JSON-RPC error response so
193	/// Claude Code surfaces the outage instead of hanging.
194	fn forward_or_error(backend: &mut Backend, req: &Value, id: Option<Value>) -> Value {
195	    let body = req.to_string();
196	    match backend.forward(&body) {
197	        Ok(v) => v,
198	        Err(e) => json!({
199	            "jsonrpc": "2.0",
200	            "id": id,
201	            "error": {
202	                "code": -32603,
203	                "message": format!("panoptd unreachable: {e:#}"),
204	            },
205	        }),
206	    }
207	}
208	
209	/// Owns the panoptd MCP session. Reconnects transparently when the
210	/// daemon's session table forgets us (a restart, an idle reap).
211	struct Backend {
212	    url: String,
213	    /// Stable agent id used to call `agent_leave` at shutdown. Matches the
214	    /// `?agent=` parameter baked into [`Self::url`]; carried as a field so
215	    /// the proxy doesn't have to re-parse its own URL.
216	    agent_id: String,
217	    /// Friendly display name, baked into [`Self::url`] for the daemon's
218	    /// implicit identify on first sight. Held for symmetry with `agent_id`;
219	    /// not used after the URL is built.
220	    #[allow(dead_code)]
221	    name: String,
222	    /// Panoptd's `mcp-session-id` header value. `None` before the first
223	    /// successful `initialize`, or after a forwarded call discovered the
224	    /// session was forgotten.
225	    session_id: Option<String>,
226	}
227	
228	impl Backend {
229	    fn new(url: String, agent_id: String, name: String) -> Self {
230	        Backend {
231	            url,
232	            agent_id,
233	            name,
234	            session_id: None,
235	        }
236	    }
237	
238	    /// Initialize a fresh panoptd session: `initialize` request, capture
239	    /// the assigned `mcp-session-id`, send the `notifications/initialized`
240	    /// follow-up. Idempotent: a successful call replaces any prior session.
241	    fn connect(&mut self) -> Result<()> {
242	        let init_body = json!({
243	            "jsonrpc": "2.0",
244	            "id": 1,
245	            "method": "initialize",
246	            "params": {
247	                "protocolVersion": PROTOCOL_VERSION,
248	                "capabilities": {},
249	                "clientInfo": {
250	                    "name": "panopt-proxy",
251	                    "version": env!("CARGO_PKG_VERSION"),
252	                },
253	            },
254	        });
255	        let resp = ureq::post(&self.url)
256	            .set("Content-Type", "application/json")
257	            .set("Accept", "application/json, text/event-stream")
258	            .send_string(&init_body.to_string())
259	            .map_err(|e| anyhow!("initialize against panoptd: {e}"))?;
260	        let sid = resp
261	            .header("mcp-session-id")
262	            .map(str::to_string)
263	            .ok_or_else(|| anyhow!("panoptd returned no mcp-session-id on initialize"))?;
264	        let _ = resp.into_string(); // discard the JSON-RPC body; we only needed the header
265	
266	        let note = json!({ "jsonrpc": "2.0", "method": "notifications/initialized" });
267	        ureq::post(&self.url)
268	            .set("Content-Type", "application/json")
269	            .set("Accept", "application/json, text/event-stream")
270	            .set("mcp-session-id", &sid)
271	            .send_string(&note.to_string())
272	            .map_err(|e| anyhow!("initialized notification to panoptd: {e}"))?;
273	
274	        self.session_id = Some(sid);
275	        Ok(())
276	    }
277	
278	    /// POST `body` (a complete JSON-RPC frame) to panoptd with the current
279	    /// session id and return the parsed response. Re-establishes the
280	    /// session on failure and retries up to [`RECONNECT_BUDGET`].
281	    fn forward(&mut self, body: &str) -> Result<Value> {
282	        let deadline = Instant::now() + RECONNECT_BUDGET;
283	        let mut backoff = RECONNECT_BACKOFF_INITIAL;
284	        let mut last_err: Option<anyhow::Error> = None;
285	
286	        loop {
287	            if Instant::now() >= deadline {
288	                return Err(last_err.unwrap_or_else(|| anyhow!("reconnect budget exhausted")));
289	            }
290	            if self.session_id.is_none() {
291	                if let Err(e) = self.connect() {
292	                    last_err = Some(e);
293	                    thread::sleep(backoff);
294	                    backoff = (backoff * 2).min(RECONNECT_BACKOFF_MAX);
295	                    continue;
296	                }
297	            }
298	            match self.try_forward(body) {
299	                Ok(v) => return Ok(v),
300	                Err(e) => {
301	                    last_err = Some(e);
302	                    // The session id is either invalid (daemon restarted)
303	                    // or the daemon is unreachable - drop it and let the
304	                    // next iteration re-initialize. Sleeping keeps us from
305	                    // hammering a daemon that is mid-restart.
306	                    self.session_id = None;
307	                    thread::sleep(backoff);
308	                    backoff = (backoff * 2).min(RECONNECT_BACKOFF_MAX);
309	                }
310	            }
311	        }
312	    }
313	
314	    fn try_forward(&self, body: &str) -> Result<Value> {
315	        let sid = self
316	            .session_id
317	            .as_ref()
318	            .ok_or_else(|| anyhow!("no panoptd session"))?;
319	        let resp = ureq::post(&self.url)
320	            .set("Content-Type", "application/json")
321	            .set("Accept", "application/json, text/event-stream")
322	            .set("mcp-session-id", sid)
323	            .send_string(body)
324	            .map_err(|e| anyhow!("forwarding to panoptd: {e}"))?;
325	        let body = resp
326	            .into_string()
327	            .context("reading panoptd response body")?;
328	        parse_response(&body)
329	    }
330	
331	    /// On shutdown, best-effort: tell the daemon we are leaving so the
332	    /// registry entry and any held locks clear immediately, then close the
333	    /// HTTP session. Errors are swallowed - the agent is exiting anyway,
334	    /// and the next sweep will eventually catch the entry if this call
335	    /// failed to land.
336	    fn farewell(&mut self) {
337	        if self.session_id.is_none() {
338	            return;
339	        }
340	        let req = json!({
341	            "jsonrpc": "2.0",
342	            "id": 99,
343	            "method": "tools/call",
344	            "params": { "name": "agent_leave", "arguments": {} },
345	        });
346	        let _ = self.try_forward(&req.to_string());
347	        if let Some(sid) = self.session_id.take() {
348	            let _ = ureq::delete(&self.url).set("mcp-session-id", &sid).call();
349	        }
350	        let _ = &self.agent_id; // silence unused-field warning if logging is added later
351	    }
352	}
353	
354	/// Parse a Streamable HTTP response body: either a bare JSON object or a
355	/// `text/event-stream` body whose `data:` lines concatenate into the
356	/// JSON-RPC frame. Mirrors the same logic in `mcpclient.rs` so behavior is
357	/// identical across the CLI's one-shot calls and the proxy's forwards.
358	fn parse_response(body: &str) -> Result<Value> {
359	    let trimmed = body.trim_start();
360	    if trimmed.starts_with('{') {
361	        return serde_json::from_str(trimmed).context("parsing JSON response");
362	    }
363	    let mut data = String::new();
364	    for line in body.lines() {
365	        if let Some(rest) = line.strip_prefix("data:") {
366	            data.push_str(rest.strip_prefix(' ').unwrap_or(rest));
367	        }
368	    }
369	    if data.is_empty() {
370	        bail!("empty response from panoptd");
371	    }
372	    serde_json::from_str(&data).context("parsing SSE data payload")
373	}
374	
375	#[cfg(test)]
376	mod tests {
377	    use super::*;
378	
379	    #[test]
380	    fn parse_response_reads_a_plain_body() {
381	        let v = parse_response(r#"{"jsonrpc":"2.0","id":1,"result":{"ok":true}}"#).unwrap();
382	        assert_eq!(v["result"]["ok"], json!(true));
383	    }
384	
385	    #[test]
386	    fn parse_response_reads_an_sse_body() {
387	        let body = "event: message\ndata: {\"jsonrpc\":\"2.0\",\"id\":1,\"result\":42}\n\n";
388	        assert_eq!(parse_response(body).unwrap()["result"], json!(42));
389	    }
390	
391	    #[test]
392	    fn build_url_percent_encodes_every_field() {
393	        let url = build_url(
394	            "127.0.0.1",
395	            7600,
396	            Path::new("/tmp/with spaces"),
397	            "user-host",
398	            "Display Name",
399	            "tok/en+with=stuff",
400	        );
401	        // Slashes, spaces, and special URL characters must be escaped so a
402	        // malformed query string cannot break the request.
403	        assert!(url.contains("ws=%2Ftmp%2Fwith%20spaces"), "{url}");
404	        assert!(url.contains("name=Display%20Name"), "{url}");
405	        assert!(url.contains("token=tok%2Fen%2Bwith%3Dstuff"), "{url}");
406	    }
407	
408	    #[test]
409	    fn dispatch_answers_initialize_locally() {
410	        let mut backend = Backend::new(
411	            "http://127.0.0.1:0/mcp".into(),
412	            "alpha".into(),
413	            "alpha".into(),
414	        );
415	        let req = json!({"jsonrpc": "2.0", "id": 7, "method": "initialize"});
416	        let resp = dispatch(&mut backend, &req).unwrap();
417	        assert_eq!(resp["id"], json!(7));
418	        assert_eq!(resp["result"]["serverInfo"]["name"], "panopt-proxy");
419	        // We did not connect to panoptd, so the session must still be empty.
420	        assert!(backend.session_id.is_none());
421	    }
422	
423	    #[test]
424	    fn dispatch_ignores_initialized_notification() {
425	        let mut backend = Backend::new(
426	            "http://127.0.0.1:0/mcp".into(),
427	            "alpha".into(),
428	            "alpha".into(),
429	        );
430	        let req = json!({"jsonrpc": "2.0", "method": "notifications/initialized"});
431	        assert!(dispatch(&mut backend, &req).is_none());
432	    }
433	
434	    #[test]
435	    fn dispatch_answers_tools_list_locally() {
436	        // No panoptd in this test; if the proxy were forwarding tools/list it
437	        // would fail. A success here means the local TOOL_SURFACE path served
438	        // the request - the whole reason step 6 of todo #88 exists.
439	        let mut backend = Backend::new(
440	            "http://127.0.0.1:0/mcp".into(),
441	            "alpha".into(),
442	            "alpha".into(),
443	        );
444	        let req = json!({"jsonrpc": "2.0", "id": 11, "method": "tools/list"});
445	        let resp = dispatch(&mut backend, &req).unwrap();
446	        assert_eq!(resp["id"], json!(11));
447	
448	        let tools = resp["result"]["tools"].as_array().expect("tools array");
449	        assert_eq!(tools.len(), panopt_tool_surface::TOOL_SURFACE.len());
450	
451	        // Spot-check shape on the first entry: every published tool must have
452	        // a non-empty name, a description, and an inputSchema that's an
453	        // object - the three fields the MCP spec requires on a Tool.
454	        for t in tools {
455	            assert!(t["name"].is_string());
456	            assert!(t["description"].is_string());
457	            assert!(t["inputSchema"].is_object(), "{t}");
458	        }
459	
460	        // We never touched panoptd, so the proxy's backend session must be
461	        // unchanged. This is the load-bearing property: a cold start with a
462	        // dead daemon should still answer tools/list.
463	        assert!(backend.session_id.is_none());
464	    }
465	}
