580	    fn update(&mut self, event: Event) -> bool {
581	        let dirty = match event {
582	            Event::PermissionRequestResult(status) => {
583	                self.permitted = matches!(status, PermissionStatus::Granted);
584	                true
585	            }
586	            Event::PaneUpdate(manifest) => {
587	                self.ingest_panes(manifest);
588	                self.rebuild_items();
589	                true
590	            }
591	            Event::Key(key) => self.handle_key(key),
592	            Event::Mouse(mouse) => self.handle_mouse(mouse),
593	            Event::Timer(_) => {
594	                // Only the Todos pane drives the initial preview - one preview
595	                // per cockpit boot is enough, and the other panes have nothing
596	                // useful to preview until the user navigates them.
597	                if self.mode == Mode::Todos
598	                    && !self.initial_preview_done
599	                    && self.slot_pane.is_some()
600	                    && self.permitted
601	                {
602	                    self.initial_preview_delay += 1;
603	                    if self.initial_preview_delay >= 2 {
604	                        self.preview_cursor();
605	                        if let Some(plugin) = self.plugin_pane {
606	                            focus_pane_with_id(plugin, false, false);
607	                        }
608	                        self.initial_preview_done = true;
609	                    }
610	                }
611	                self.reload_data();
612	                self.rebuild_items();
613	                // PaneUpdate-driven `sync_pane_titles` only fires when Zellij
614	                // sends a pane manifest - typing into the form does not. Without
615	                // this call, every right-pane title (most visibly a freshly
616	                // promoted "Todo #N - ...") would freeze at whatever value it
617	                // held when the last PaneUpdate landed, even after autosaves
618	                // have refreshed `self.todos` from the projection.
619	                self.sync_pane_titles();
620	                set_timeout(1.0);
621	                true
622	            }
623	            _ => false,
624	        };
625	        // The frame title is set via the `rename_plugin_pane` plugin command,
626	        // which serializes itself onto stdout for the host to read. The host
627	        // only consumes those command bytes BETWEEN events - issuing a plugin
628	        // command from inside `render` makes the JSON leak in as a phantom
629	        // content row and shifts every item down by one. So sync the title
630	        // only here, never in `render`.
631	        if dirty {
