fn pane_is_visible(&self, pane: PaneId) -> bool {
    self.panes.iter().any(|p| p.id == pane && !p.suppressed)
}

fn viewer_slot_of(&self, pane: PaneId) -> Option<String> {
    self.panes
        .iter()
        .find(|p| p.id == pane)
        .and_then(|p| p.viewer_slot.clone())
}

